INSERT INTO pages (title, slug, summary, content, status, published_at)
VALUES
    ('Gioi thieu cong ty', 'gioi-thieu-cong-ty', 'Trang gioi thieu tong quan ve Hanoi Survey.', '<p>Hanoi Survey cung cap dich vu khao sat, thi nghiem va quan trac cho cac du an dan dung, cong nghiep va ha tang.</p><p>Du lieu nay duoc tao de kiem tra giao dien va API.</p>', 'PUBLISHED', DATE_SUB(NOW(), INTERVAL 120 DAY)),
    ('Nang luc nhan su', 'nang-luc-nhan-su', 'Thong tin ve doi ngu ky su va chuyen gia.', '<p>Doi ngu gom cac ky su dia chat, dia hinh, thuy van va thi nghiem hien truong.</p>', 'PUBLISHED', DATE_SUB(NOW(), INTERVAL 110 DAY)),
    ('Nang luc thiet bi', 'nang-luc-thiet-bi', 'Tong hop thiet bi khoan, do dac va thi nghiem.', '<p>He thong thiet bi duoc dau tu dong bo phuc vu nhieu loai hinh du an.</p>', 'PUBLISHED', DATE_SUB(NOW(), INTERVAL 105 DAY)),
    ('Quy trinh trien khai du an', 'quy-trinh-trien-khai-du-an', 'Mo ta cac buoc trien khai khao sat ngoai nghiem thu.', '<p>Quy trinh bao gom tiep nhan yeu cau, khao sat hien truong, lap bao cao va ban giao ho so.</p>', 'PUBLISHED', DATE_SUB(NOW(), INTERVAL 95 DAY)),
    ('Cam ket an toan lao dong', 'cam-ket-an-toan-lao-dong', 'Chinh sach an toan khi thi cong va khao sat.', '<p>An toan lao dong va kiem soat rui ro la yeu to bat buoc trong moi cong trinh.</p>', 'PUBLISHED', DATE_SUB(NOW(), INTERVAL 80 DAY)),
    ('Chinh sach bao mat', 'chinh-sach-bao-mat', 'Noi dung chinh sach bao mat thong tin khach hang.', '<p>Thong tin lien he va du lieu khach hang duoc luu tru va xu ly theo quy dinh noi bo.</p>', 'PUBLISHED', DATE_SUB(NOW(), INTERVAL 60 DAY)),
    ('Dieu khoan su dung', 'dieu-khoan-su-dung', 'Dieu khoan su dung website va dich vu.', '<p>Trang du lieu mau phuc vu kiem tra kha nang hien thi noi dung dai.</p>', 'DRAFT', NULL),
    ('Tuyen dung ky su hien truong', 'tuyen-dung-ky-su-hien-truong', 'Thong tin tuyen dung noi bo.', '<p>Can bo sung nhan su cho cac du an khao sat dia chat va dia hinh tai mien Bac.</p>', 'DRAFT', NULL);
INSERT INTO posts (category_id, title, slug, excerpt, content, status, published_at)
VALUES
    ((SELECT id FROM post_categories WHERE slug = 'tin-tuc'), 'Khoi cong goi khao sat cao toc phia Bac', 'khoi-cong-goi-khao-sat-cao-toc-phia-bac', 'Du an khao sat phuc vu lap bao cao tien kha thi cho tuyen cao toc moi.', '<p>Doan tu van da huy dong may khoan, thiet bi do dac va nhan su de trien khai trong 45 ngay.</p>', 'PUBLISHED', DATE_SUB(NOW(), INTERVAL 40 DAY)),
    ((SELECT id FROM post_categories WHERE slug = 'tin-tuc'), 'Hoan thanh khao sat nha may tai Hung Yen', 'hoan-thanh-khao-sat-nha-may-tai-hung-yen', 'Hoan thanh khoi luong khoan va thi nghiem hien truong cho khu cong nghiep moi.', '<p>Ket qua so bo cho thay dia tang phu hop voi phuong an mong coc du kien.</p>', 'PUBLISHED', DATE_SUB(NOW(), INTERVAL 36 DAY)),
    ((SELECT id FROM post_categories WHERE slug = 'tin-tuc'), 'Ban giao ho so du an khu do thi ven song', 'ban-giao-ho-so-du-an-khu-do-thi-ven-song', 'Ho so bao gom bao cao dia chat, dia hinh va de xuat giai phap nen mong.', '<p>Chu dau tu danh gia cao toc do trien khai va chat luong tai lieu.</p>', 'PUBLISHED', DATE_SUB(NOW(), INTERVAL 31 DAY)),
    ((SELECT id FROM post_categories WHERE slug = 'tin-tuc'), 'Mo rong phong thi nghiem vat lieu', 'mo-rong-phong-thi-nghiem-vat-lieu', 'Bo sung thiet bi phuc vu cac chi tieu nen, be tong va cat da.', '<p>Phong thi nghiem moi giup tang cong suat va rut ngan tien do tra ket qua.</p>', 'PUBLISHED', DATE_SUB(NOW(), INTERVAL 27 DAY)),
    ((SELECT id FROM post_categories WHERE slug = 'tin-tuc'), 'Khai truong van phong du an tai Quang Ninh', 'khai-truong-van-phong-du-an-tai-quang-ninh', 'Van phong ho tro trien khai cac du an ha tang va cong nghiep khu vuc Dong Bac.', '<p>Don vi bo tri nhan su ky thuat va dieu phoi truc tiep tai cong truong.</p>', 'PUBLISHED', DATE_SUB(NOW(), INTERVAL 21 DAY)),
    ((SELECT id FROM post_categories WHERE slug = 'tin-tuc'), 'Cap nhat danh muc thiet bi quy 2', 'cap-nhat-danh-muc-thiet-bi-quy-2', 'Them nhieu thiet bi khoan va do dac phuc vu du an lon.', '<p>Danh muc cap nhat giup doi thi cong dap ung dong thoi nhieu goi thau.</p>', 'DRAFT', NULL),
    ((SELECT id FROM post_categories WHERE slug = 'kien-thuc'), 'Cach doc bao cao khao sat dia chat cong trinh', 'cach-doc-bao-cao-khao-sat-dia-chat-cong-trinh', 'Tong hop nhung muc quan trong trong bao cao dia chat.', '<p>Can chu y mat cat dia tang, muc nuoc ngam, chi tieu co ly va khuyen nghi nen mong.</p>', 'PUBLISHED', DATE_SUB(NOW(), INTERVAL 18 DAY)),
    ((SELECT id FROM post_categories WHERE slug = 'kien-thuc'), 'Phan biet khao sat dia hinh va do dac hoan cong', 'phan-biet-khao-sat-dia-hinh-va-do-dac-hoan-cong', 'Hai hang muc co muc tieu va san pham ban giao khac nhau.', '<p>Khao sat dia hinh phuc vu thiet ke, con hoan cong phuc vu nghiem thu hien trang sau thi cong.</p>', 'PUBLISHED', DATE_SUB(NOW(), INTERVAL 15 DAY)),
    ((SELECT id FROM post_categories WHERE slug = 'kien-thuc'), 'Khi nao can thi nghiem CPTu', 'khi-nao-can-thi-nghiem-cptu', 'CPTu phu hop voi nen dat yeu va can xac dinh suc khang mui lien tuc.', '<p>Phuong phap nay thu duoc du lieu nhanh va giam so luong mau xao tron.</p>', 'PUBLISHED', DATE_SUB(NOW(), INTERVAL 12 DAY)),
    ((SELECT id FROM post_categories WHERE slug = 'kien-thuc'), 'Quan trac lun cong trinh gom nhung gi', 'quan-trac-lun-cong-trinh-gom-nhung-gi', 'Tong hop cac hang muc quan trac lun, nghieng, dich chuyen ngang.', '<p>Can lap ke hoach tan suat do, moc quan trac va nguong canh bao ngay tu dau du an.</p>', 'PUBLISHED', DATE_SUB(NOW(), INTERVAL 9 DAY)),
    ((SELECT id FROM post_categories WHERE slug = 'kien-thuc'), 'Lua chon phuong an khoan lay mau cho nen dat phuc tap', 'lua-chon-phuong-an-khoan-lay-mau-cho-nen-dat-phuc-tap', 'De xuat theo tung dieu kien dia tang va muc nuoc ngam.', '<p>Can can nhac mau nguyen dang, chieu sau khoan va dieu kien tiep can hien truong.</p>', 'PUBLISHED', DATE_SUB(NOW(), INTERVAL 6 DAY)),
    ((SELECT id FROM post_categories WHERE slug = 'kien-thuc'), 'Checklist nghiem thu cong tac khao sat', 'checklist-nghiem-thu-cong-tac-khao-sat', 'Danh sach tai lieu va buoc kiem tra khi nghiem thu.', '<p>Day la bai viet nhap de kiem tra trang thai ban nhap.</p>', 'DRAFT', NULL);
INSERT INTO services (category_id, title, slug, overview, content, icon, cover_image_path, status, published_at)
VALUES
    ((SELECT id FROM service_categories WHERE slug = 'khao-sat-dia-chat-cong-trinh'), 'Khao sat dia chat cho nha cao tang', 'khao-sat-dia-chat-cho-nha-cao-tang', 'Khoan, lay mau va thi nghiem phuc vu thiet ke mong nha cao tang.', '<p>Goi dich vu bao gom khoan xoay rua, SPT, mau nguyen dang, lap bao cao dia chat va khuyen nghi giai phap mong.</p>', 'drill', 'seed/media/service-drilling-rig.jpg', 'PUBLISHED', DATE_SUB(NOW(), INTERVAL 70 DAY)),
    ((SELECT id FROM service_categories WHERE slug = 'khao-sat-dia-chat-cong-trinh'), 'Khao sat dia chat cho nha xuong cong nghiep', 'khao-sat-dia-chat-cho-nha-xuong-cong-nghiep', 'Danh gia nen dat cho nha may, kho va cong trinh san xuat.', '<p>Phu hop cac du an khu cong nghiep can tien do nhanh va bao cao ro rang.</p>', 'factory', 'seed/media/service-drilling-rig.jpg', 'PUBLISHED', DATE_SUB(NOW(), INTERVAL 64 DAY)),
    ((SELECT id FROM service_categories WHERE slug = 'khao-sat-dia-hinh'), 'Do dac ban do dia hinh bang drone', 'do-dac-ban-do-dia-hinh-bang-drone', 'Bay chup, xu ly du lieu va thanh lap ban do dia hinh so.', '<p>Dich vu phuc vu quy hoach, giao thong, khu do thi va cong trinh cong nghiep.</p>', 'map', 'seed/media/service-topography-drone.jpg', 'PUBLISHED', DATE_SUB(NOW(), INTERVAL 58 DAY)),
    ((SELECT id FROM service_categories WHERE slug = 'khao-sat-dia-hinh'), 'Cam moc va luoi khong che thi cong', 'cam-moc-va-luoi-khong-che-thi-cong', 'Lap luoi toa do, cao do va moc dinh vi thi cong.', '<p>Dam bao so lieu chinh xac va dong bo trong suot qua trinh thi cong.</p>', 'pin', 'seed/media/service-topography-drone.jpg', 'PUBLISHED', DATE_SUB(NOW(), INTERVAL 52 DAY)),
    ((SELECT id FROM service_categories WHERE slug = 'khao-sat-dia-chat-thuy-van'), 'Khao sat muc nuoc ngam va dia chat thuy van', 'khao-sat-muc-nuoc-ngam-va-dia-chat-thuy-van', 'Quan trac muc nuoc, danh gia dong chay va dac diem tang chua nuoc.', '<p>Du lieu giup tinh toan ha muc nuoc, chong tham va lua chon giai phap thi cong.</p>', 'water', 'seed/media/service-lab-testing.jpg', 'PUBLISHED', DATE_SUB(NOW(), INTERVAL 46 DAY)),
    ((SELECT id FROM service_categories WHERE slug = 'thi-nghiem-chuyen-nganh-xay-dung'), 'Thi nghiem co ly dat da trong phong', 'thi-nghiem-co-ly-dat-da-trong-phong', 'Thuc hien cac chi tieu co ly va suc chiu tai cua mau dat da.', '<p>He thong phong thi nghiem phuc vu nhieu chi tieu tu co ban den chuyen sau.</p>', 'flask', 'seed/media/service-lab-testing.jpg', 'PUBLISHED', DATE_SUB(NOW(), INTERVAL 39 DAY)),
    ((SELECT id FROM service_categories WHERE slug = 'thi-nghiem-chuyen-nganh-xay-dung'), 'Thi nghiem hien truong SPT va CPTu', 'thi-nghiem-hien-truong-spt-va-cptu', 'Ket hop cac phuong phap de danh gia suc khang va dia tang tai cho.', '<p>Goi dich vu phu hop cac du an can du lieu lien tuc va do tin cay cao.</p>', 'gauge', 'seed/media/service-lab-testing.jpg', 'PUBLISHED', DATE_SUB(NOW(), INTERVAL 34 DAY)),
    ((SELECT id FROM service_categories WHERE slug = 'quan-trac-cong-trinh'), 'Quan trac lun nghieng cong trinh', 'quan-trac-lun-nghieng-cong-trinh', 'Theo doi bien dang cong trinh trong qua trinh thi cong va van hanh.', '<p>He thong bao cao dinh ky va canh bao som cac bien dong bat thuong.</p>', 'radar', 'seed/media/project-highway.jpg', 'PUBLISHED', DATE_SUB(NOW(), INTERVAL 28 DAY)),
    ((SELECT id FROM service_categories WHERE slug = 'tu-van-giam-sat-khao-sat'), 'Tu van giam sat cong tac khao sat', 'tu-van-giam-sat-cong-tac-khao-sat', 'Giam sat chat luong khoi luong va quy trinh khao sat.', '<p>Dam bao ho so khao sat dat yeu cau phap ly va ky thuat cho buoc thiet ke.</p>', 'shield', 'seed/media/project-factory.jpg', 'PUBLISHED', DATE_SUB(NOW(), INTERVAL 22 DAY)),
    ((SELECT id FROM service_categories WHERE slug = 'xay-lap'), 'Thi cong xu ly nen dat yeu', 'thi-cong-xu-ly-nen-dat-yeu', 'Ho tro thi cong cac giai phap gia co va xu ly nen.', '<p>Du lieu nhap de kiem tra danh sach dich vu ban nhap tren trang quan tri.</p>', 'build', 'seed/media/project-housing.jpg', 'DRAFT', NULL);
